import software.amazon.awssdk.auth.credentials.ProfileCredentialsProvider
import software.amazon.awssdk.regions.Region
import software.amazon.awssdk.services.s3.S3Client
import software.amazon.awssdk.services.s3.model._

object AwsService {
  def main(args: Array[String]): Unit = {
    // Load credentials from the default profile in AWS credentials file
    val credentialsProvider = ProfileCredentialsProvider.create()

    // Create a client for S3 with specified region and credentials
    val s3Client: S3Client = S3Client.builder()
      .region(Region.US_EAST_1)
      .credentialsProvider(credentialsProvider)
      .build()

    // List buckets example
    listBuckets(s3Client)

    // Upload a file example
    uploadFile(s3Client, "bucket-name", "path/to/local/file.txt", "s3-object-key")

    s3Client.close()
  }

  def listBuckets(client: S3Client): Unit = {
    println("Listing buckets:")
    client.listBuckets().buckets.forEach(bucket => println(bucket.name))
  }

  def uploadFile(
      client: S3Client,
      bucketName: String,
      localFilePath: String,
      s3ObjectKey: String
  ): Unit = {
    println(s"Uploading file $localFilePath to s3://$bucketName/$s3ObjectKey")
    val request = PutObjectRequest.builder()
      .bucket(bucketName)
      .key(s3ObjectKey)
      .build()

    client.putObject(request, java.nio.file.Paths.get(localFilePath))
    println("File uploaded successfully.")
  }
}